#include "interface.h"
#include <cuda_runtime.h>

namespace {

__global__ void histogram_shared_kernel(const unsigned char* input, unsigned int* output, int n) {
    // Use shared memory for local histogram to reduce global memory contention.
    // Padding to 256 + 16 to help avoid some bank conflicts, though 256 is power-of-2.
    __shared__ unsigned int s_hist[256 + 16];

    // Initialize shared memory
    for (int i = threadIdx.x; i < 256; i += blockDim.x) {
        s_hist[i] = 0;
    }
    __syncthreads();

    // Grid-stride loop to process input
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    for (int idx = tid; idx < n; idx += stride) {
        s_hist[input[idx]]++;
    }

    __syncthreads();

    // Merge local shared histogram into global output
    for (int i = threadIdx.x; i < 256; i += blockDim.x) {
        atomicAdd(output + i, s_hist[i]);
    }
}

}  // namespace

void histogram256_u8(const unsigned char* input, unsigned int* output, int n, int iters) {
    // Tuning parameters
    const int kBlock = 256;
    // Use a grid size that provides good occupancy across different architectures
    const int grid = 256;

    for (int iter = 0; iter < iters; ++iter) {
        cudaMemsetAsync(output, 0, 256 * sizeof(unsigned int), 0);
        histogram_shared_kernel<<<grid, kBlock>>>(input, output, n);
    }
}
